query:
UPDATE content_runs 
SET status = 'failed', updated_at = NOW()
WHERE status IN ('assembling', 'generating_video', 'researching', 'generating_slides', 'pending')
  AND status NOT IN ('completed', 'failed', 'review', 'pending_post');
SELECT id, status, run_slot, created_at FROM content_runs ORDER BY id DESC LIMIT 10;

